function owner() public view returns (address result) {
    uint256 cachedChainId = _cachedChainId;
    assembly {
        // ... read tokenContract & tokenId from bytecode ...
        if eq(mload(0x00), cachedChainId) {
            // only do the call on the correct fork
            result := mul(
                mload(0x20),
                and(
                    gt(returndatasize(), 0x1f),
                    staticcall(gas(), tokenContract, ..., 0x20, 0x20)
                )
            )
        }
        // else: result stays 0 — wrong fork, no owner
    }
}
